// js/car.js
// Vehicle log module — fuel, service, odometer tracking.

const CarModule = (function () {
  'use strict';

  const STORAGE_KEY   = () => 'car_' + window.AppState.username;
  const FIREBASE_PATH = () => 'car/' + window.AppState.username;
  const FUEL_RATE_KEY = () => 'car_fuel_rate_' + window.AppState.username;

  /* ── Render ───────────────────────────────────────────────── */
  function render() {
    document.getElementById('app').innerHTML = `
      <div class="fade-in">
        <div class="page-header">
          <h2>🚗 Car Log</h2>
          <p>Track fuel, service, and mileage</p>
        </div>

        <!-- Summary cards -->
        <div class="stat-cards" id="car-stats">
          <div class="stat-card">
            <div class="stat-label">Total Distance</div>
            <div class="stat-value" id="cs-dist">0 km</div>
          </div>
          <div class="stat-card">
            <div class="stat-label">Total Fuel</div>
            <div class="stat-value" id="cs-fuel">0 L</div>
          </div>
          <div class="stat-card">
            <div class="stat-label">Fuel Cost</div>
            <div class="stat-value" id="cs-fcost">₹0</div>
          </div>
          <div class="stat-card">
            <div class="stat-label">Service Cost</div>
            <div class="stat-value" id="cs-scost">₹0</div>
          </div>
          <div class="stat-card">
            <div class="stat-label">Avg Mileage</div>
            <div class="stat-value" id="cs-mileage">— km/L</div>
          </div>
        </div>

        <form class="form-card" id="car-form" novalidate>
          <div class="card-title">New Entry</div>
          <div id="car-alert"></div>

          <div class="form-row">
            <div class="form-group">
              <label for="car-date">Date <span style="color:var(--color-danger)">*</span></label>
              <input type="date" id="car-date" />
            </div>
            <div class="form-group">
              <label for="car-odometer">Odometer (km) <span style="color:var(--color-danger)">*</span></label>
              <input type="number" id="car-odometer" placeholder="13500" min="0" step="1" />
            </div>
          </div>

          <!-- Fuel section toggle -->
          <div class="collapsible-header" id="fuel-toggle">
            <span>⛽ Fuel Entry (optional)</span>
            <span id="fuel-toggle-icon">▶</span>
          </div>
          <div class="collapsible-body" id="fuel-section">
            <div class="form-row">
              <div class="form-group">
                <label for="car-fuel-rate">Fuel Rate (₹/L) <span class="text-xs text-muted">auto-saved</span></label>
                <input type="number" id="car-fuel-rate" placeholder="e.g. 103.50" min="0" step="0.01" />
              </div>
              <div class="form-group">
                <label for="car-station">Station</label>
                <input type="text" id="car-station" placeholder="e.g. HP Majestic" />
              </div>
            </div>
            <p class="text-xs text-muted mb-sm">Enter <strong>either</strong> fuel volume or total cost. The other is calculated from the rate.</p>
            <div class="form-row">
              <div class="form-group">
                <label for="car-fuel-vol">Fuel Volume (L)</label>
                <input type="number" id="car-fuel-vol" placeholder="0" min="0" step="0.01" />
              </div>
              <div class="form-group">
                <label for="car-fuel-cost">Total Cost (₹)</label>
                <input type="number" id="car-fuel-cost" placeholder="0" min="0" step="0.01" />
              </div>
            </div>
            <div class="toggle-row">
              <input type="checkbox" id="car-full-tank" />
              <label for="car-full-tank">Full tank</label>
            </div>
          </div>

          <hr class="divider" />

          <!-- Service section toggle -->
          <div class="collapsible-header" id="service-toggle">
            <span>🔧 Service Entry (optional)</span>
            <span id="service-toggle-icon">▶</span>
          </div>
          <div class="collapsible-body" id="service-section">
            <div class="form-row">
              <div class="form-group">
                <label for="car-svc-cost">Service Cost (₹)</label>
                <input type="number" id="car-svc-cost" placeholder="0" min="0" step="0.01" />
              </div>
              <div class="form-group">
                <label for="car-svc-details">Service Details</label>
                <input type="text" id="car-svc-details" placeholder="e.g. Oil change, air filter" />
              </div>
            </div>
          </div>

          <hr class="divider" />

          <div class="form-row">
            <div class="form-group">
              <label for="car-mode">Driving Mode</label>
              <select id="car-mode">
                <option value="City" selected>City</option>
                <option value="Highway">Highway</option>
                <option value="Mixed">Mixed</option>
              </select>
            </div>
            <div class="form-group">
              <label for="car-notes">Notes</label>
              <input type="text" id="car-notes" placeholder="Optional notes" maxlength="200" />
            </div>
          </div>

          <button type="submit" class="btn btn-primary">Save Entry</button>
        </form>

        <div class="card">
          <div class="card-title">📋 Log</div>
          <div class="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>Date</th>
                  <th class="td-num">ODO</th>
                  <th class="td-num">Driven</th>
                  <th class="td-num">Cost</th>
                  <th>Notes</th>
                </tr>
              </thead>
              <tbody id="car-tbody"><tr><td colspan="5" class="text-muted text-sm text-center">Loading…</td></tr></tbody>
            </table>
          </div>
        </div>
      </div>
    `;

    // Set today's date as default
    const today = new Date().toISOString().slice(0, 10);
    document.getElementById('car-date').value = today;

    // Load saved fuel rate
    const savedRate = localStorage.getItem(FUEL_RATE_KEY());
    if (savedRate) {
      document.getElementById('car-fuel-rate').value = savedRate;
    }

    // Collapsible toggles
    setupToggle('fuel-toggle', 'fuel-section', 'fuel-toggle-icon');
    setupToggle('service-toggle', 'service-section', 'service-toggle-icon');

    document.getElementById('car-form').addEventListener('submit', function (e) {
      e.preventDefault();
      submit();
    });

    // Auto-calculate: when volume changes, compute cost from rate
    document.getElementById('car-fuel-vol').addEventListener('input', function () {
      autoCalcFromVolume();
    });

    // Auto-calculate: when cost changes, compute volume from rate
    document.getElementById('car-fuel-cost').addEventListener('input', function () {
      autoCalcFromCost();
    });

    loadData();
  }

  function setupToggle(headerId, bodyId, iconId) {
    document.getElementById(headerId).addEventListener('click', function () {
      const body = document.getElementById(bodyId);
      const icon = document.getElementById(iconId);
      body.classList.toggle('open');
      icon.textContent = body.classList.contains('open') ? '▼' : '▶';
    });
  }

  function autoCalcFromVolume() {
    const vol  = parseFloat(document.getElementById('car-fuel-vol').value)  || 0;
    const rate = parseFloat(document.getElementById('car-fuel-rate').value) || 0;
    if (vol > 0 && rate > 0) {
      document.getElementById('car-fuel-cost').value = (vol * rate).toFixed(2);
    }
  }

  function autoCalcFromCost() {
    const cost = parseFloat(document.getElementById('car-fuel-cost').value) || 0;
    const rate = parseFloat(document.getElementById('car-fuel-rate').value) || 0;
    if (cost > 0 && rate > 0) {
      document.getElementById('car-fuel-vol').value = (cost / rate).toFixed(2);
    }
  }

  /* ── Submit ───────────────────────────────────────────────── */
  async function submit() {
    const date      = document.getElementById('car-date').value;
    const odometer  = parseFloat(document.getElementById('car-odometer').value) || 0;
    const fuelRate  = parseFloat(document.getElementById('car-fuel-rate').value) || 0;
    let   fuelVol   = parseFloat(document.getElementById('car-fuel-vol').value)   || 0;
    let   fuelCost  = parseFloat(document.getElementById('car-fuel-cost').value)  || 0;
    const fullTank  = document.getElementById('car-full-tank').checked;
    const station   = document.getElementById('car-station').value.trim();
    const svcCost   = parseFloat(document.getElementById('car-svc-cost').value)    || 0;
    const svcDetails = document.getElementById('car-svc-details').value.trim();
    const mode      = document.getElementById('car-mode').value;
    const notes     = document.getElementById('car-notes').value.trim();

    // Validation
    if (!date) {
      showAlert('car-alert', 'Date is required.', 'error');
      return;
    }
    if (!odometer || odometer <= 0) {
      showAlert('car-alert', 'Odometer reading must be greater than 0.', 'error');
      return;
    }

    const arr = await getEntries();
    const lastOdo = arr.length > 0 ? arr[arr.length - 1].odometer : 0;

    if (odometer < lastOdo) {
      showAlert('car-alert', `Odometer (${odometer}) cannot be less than last entry (${lastOdo}).`, 'error');
      return;
    }

    // If either volume or cost is provided, compute the other from rate
    if ((fuelVol > 0 || fuelCost > 0) && fuelRate <= 0) {
      showAlert('car-alert', 'Fuel rate is required when entering fuel data.', 'error');
      return;
    }

    if (fuelVol > 0 && fuelCost === 0 && fuelRate > 0) {
      fuelCost = parseFloat((fuelVol * fuelRate).toFixed(2));
    } else if (fuelCost > 0 && fuelVol === 0 && fuelRate > 0) {
      fuelVol = parseFloat((fuelCost / fuelRate).toFixed(2));
    }

    // Save the fuel rate for reuse
    if (fuelRate > 0) {
      localStorage.setItem(FUEL_RATE_KEY(), String(fuelRate));
    }

    const ppu = fuelRate > 0 ? fuelRate : (fuelVol > 0 ? parseFloat(DIV(fuelCost, fuelVol).toFixed(2)) : 0);

    clearAlert('car-alert');

    const entry = processCarData(arr, {
      date, odometer, fuelVol, fuelCost, ppu, fullTank, station,
      svcCost, svcDetails, mode, notes,
    });

    arr.push(entry);

    // Write to Firebase and update local cache
    try {
      await firebasePost(FIREBASE_PATH(), entry);
    } catch (e) {
      console.warn('Firebase write failed:', e);
    }
    localStorage.setItem(STORAGE_KEY(), JSON.stringify(arr));

    showAlert('car-alert', 'Entry saved! 🚗', 'success');

    // Reset optional fields (keep fuel rate)
    document.getElementById('car-fuel-vol').value   = '';
    document.getElementById('car-fuel-cost').value  = '';
    document.getElementById('car-full-tank').checked    = false;
    document.getElementById('car-station').value    = '';
    document.getElementById('car-svc-cost').value   = '';
    document.getElementById('car-svc-details').value = '';
    document.getElementById('car-mode').value       = 'City';
    document.getElementById('car-notes').value      = '';

    renderSummary(arr);
    renderTable(arr);
  }

  /* ── Process car entry ────────────────────────────────────── */
  function processCarData(arr, raw) {
    const lastEntry = arr.length > 0 ? arr[arr.length - 1] : null;
    const lastOdo   = lastEntry ? lastEntry.odometer : 0;
    const distanceTraveled = lastEntry ? raw.odometer - lastOdo : 0;

    // Mileage: only if BOTH last entry and current entry are full tank, distance > 0, and fuel > 0
    let mileage = null;
    if (lastEntry && lastEntry.fullTank && raw.fullTank && distanceTraveled > 0 && raw.fuelVol > 0) {
      mileage = parseFloat(DIV(distanceTraveled, raw.fuelVol).toFixed(2));
    }

    // Entry type
    let entryType = 'odometer';
    if (raw.fuelVol > 0 && raw.svcCost > 0) entryType = 'fuel+service';
    else if (raw.fuelVol > 0)               entryType = 'fuel';
    else if (raw.svcCost > 0)               entryType = 'service';

    const prevId = lastEntry ? lastEntry.entry_id : 0;

    return {
      entry_id:          prevId + 1,
      date:              raw.date,
      odometer:          raw.odometer,
      distanceTraveled:  distanceTraveled,
      fuelVolume:        raw.fuelVol,
      totalCost:         raw.fuelCost,
      pricePerUnit:      raw.ppu,
      fullTank:          raw.fullTank,
      station:           raw.station,
      serviceCost:       raw.svcCost,
      serviceDetails:    raw.svcDetails,
      drivingMode:       raw.mode,
      notes:             raw.notes,
      mileage,
      entryType,
      timestamp:         getKolkataTimestamp(),
    };
  }

  /* ── Load ─────────────────────────────────────────────────── */
  async function loadData() {
    const arr = await getEntries();

    if (arr.length === 0) {
      const tbody = document.getElementById('car-tbody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="5" class="text-muted text-sm text-center">No entries yet.</td></tr>';
      return;
    }

    renderSummary(arr);
    renderTable(arr);
  }

  /* ── Summary ──────────────────────────────────────────────── */
  function renderSummary(arr) {
    let totalDist = 0, totalFuelVol = 0, totalFuelCost = 0, totalSvcCost = 0;

    arr.forEach(function (e) {
      totalDist     += (e.distanceTraveled || 0);
      totalFuelVol  += (e.fuelVolume  || 0);
      totalFuelCost += (e.totalCost   || 0);
      totalSvcCost  += (e.serviceCost || 0);
    });

    // Weighted average mileage: total distance / total fuel consumed
    const avgMileage = totalFuelVol > 0
      ? DIV(totalDist, totalFuelVol).toFixed(2)
      : null;

    document.getElementById('cs-dist').textContent    = totalDist.toLocaleString() + ' km';
    document.getElementById('cs-fuel').textContent    = totalFuelVol.toFixed(1) + ' L';
    document.getElementById('cs-fcost').textContent   = getINR(totalFuelCost);
    document.getElementById('cs-scost').textContent   = getINR(totalSvcCost);
    document.getElementById('cs-mileage').textContent = avgMileage ? avgMileage + ' km/L' : '— km/L';
  }

  /* ── Table ────────────────────────────────────────────────── */
  function renderTable(arr) {
    const tbody = document.getElementById('car-tbody');
    if (!tbody) return;

    tbody.innerHTML = arr.slice().reverse().map(function (e) {
      var totalCost = (e.totalCost || 0) + (e.serviceCost || 0);

      // Notes column: "Fuel" for fuel entries, service details for service, combine if both
      var noteParts = [];
      if (e.fuelVolume > 0) noteParts.push('Fuel');
      if (e.serviceCost > 0 && e.serviceDetails) noteParts.push(e.serviceDetails);
      else if (e.serviceCost > 0) noteParts.push('Service');
      if (e.notes) noteParts.push(e.notes);
      var noteText = noteParts.join(' | ') || '—';

      var driven = e.distanceTraveled || 0;
      return `<tr>
        <td style="white-space:nowrap">${formatDate(e.date)}</td>
        <td class="td-num">${e.odometer.toLocaleString()}</td>
        <td class="td-num">${driven > 0 ? driven.toLocaleString() + ' km' : '—'}</td>
        <td class="td-num">${totalCost > 0 ? getINR(totalCost) : '—'}</td>
        <td>${escapeHtml(noteText)}</td>
      </tr>`;
    }).join('');
  }

  /* ── Storage helpers ──────────────────────────────────────── */
  async function getEntries() {
    try {
      const data = await firebaseGet(FIREBASE_PATH());
      const arr  = data ? objectToArray(data) : [];
      localStorage.setItem(STORAGE_KEY(), JSON.stringify(arr));
      return arr;
    } catch (e) {
      console.warn('Firebase read failed, using localStorage:', e);
      try {
        return JSON.parse(localStorage.getItem(STORAGE_KEY())) || [];
      } catch (_) { return []; }
    }
  }

  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  return { render, submit, loadData };
}());

export { CarModule };
